 13→    --hero-glow-border: rgba(255, 180, 50, 0.4);
 14→    --hero-glow-core: rgba(255, 190, 60, 0.3);
 15→    --hero-glow-tight: rgba(255, 170, 40, 0.28);
 16→    --hero-glow-mid: rgba(255, 150, 25, 0.16);
 17→    --hero-glow-wide: rgba(255, 130, 15, 0.08);
