 39→    font-family: var(--font-ui);
 40→    font-size: 0.68rem;
 41→    font-weight: 700;
 42→    letter-spacing: 0.08rem;
 43→    text-transform: uppercase;
 44→    color: var(--text-faint);
 45→}
 46→.explore-section-title::after{
