 68→    position: relative;
 69→    width: 100%;
 70→}
 71→
 72→.explore-hero-card{
 73→    position: relative;
 74→    display: flex;
 75→    flex-direction: column;
 76→    width: 100%;
 77→    border-radius: 14px;
 78→    overflow: hidden;
 79→    cursor: pointer;
 80→    background: var(--bg-card);
 81→    border: 1.5px solid var(--hero-glow-border);
 82→    box-shadow:
 83→        0 0 8px 2px var(--hero-glow-tight),
 84→        0 0 24px 6px var(--hero-glow-mid),
 85→        0 0 56px 14px var(--hero-glow-wide),
 86→        0 0 100px 28px var(--hero-glow-ambient);
 87→    transition: transform 0.3s ease, box-shadow 0.3s ease;
 88→    z-index: 1;
 89→}
 90→.explore-hero-card:hover{
 91→    transform: translateY(-3px);
 92→    box-shadow:
 93→        0 0 12px 4px var(--hero-glow-tight),
 94→        0 0 32px 10px var(--hero-glow-mid),
 95→        0 0 70px 20px var(--hero-glow-wide),
 96→        0 0 120px 36px var(--hero-glow-ambient);
 97→}
