 99→/* Diffused solar corona glow behind card */
100→.explore-hero-glow{
101→    position: absolute;
102→    inset: -28px;
103→    border-radius: 42px;
104→    z-index: 0;
105→    pointer-events: none;
106→    background:
107→        radial-gradient(
108→            ellipse 90% 70% at 50% 50%,
109→            var(--hero-glow-core) 0%,
110→            var(--hero-glow-mid) 30%,
111→            var(--hero-glow-wide) 55%,
112→            var(--hero-glow-ambient) 75%,
113→            transparent 90%
114→        );
115→    filter: blur(20px);
116→}
117→
118→/* Hero image */
119→.explore-hero-image-wrap{
120→    position: relative;
121→    width: 100%;
122→    max-height: 260px;
123→    overflow: hidden;
124→    z-index: 1;
125→}
