127→    width: 100%;
128→    height: 100%;
129→    max-height: 260px;
130→    object-fit: cover;
131→    display: block;
132→}
133→.explore-hero-image-overlay{
134→    position: absolute;
135→    inset: 0;
136→    background: linear-gradient(
137→        to bottom,
138→        transparent 40%,
139→        var(--bg-card) 100%
140→    );
141→    pointer-events: none;
142→}
143→
144→/* Hero body */
